const input = $json;

const systemPrompt = `# Rol
Eres el Verdict Agent del sistema Innexia AI Strategic Analysis Engine v5.

# Objetivo
Emitir un veredicto ejecutivo basado en los outputs de BMC, Strategy, Finance y Risks.

# Instrucciones
- Tu decisión debe estar basada en los insumos recibidos.
- Las decisiones permitidas son:
  - avanzar
  - avanzar_con_piloto
  - rediseñar_antes_de_avanzar
  - no_avanzar_por_ahora
- Debes incluir razones y condiciones para proceder.
- No expliques tu razonamiento.
- Devuelve únicamente JSON válido.

# Formato de salida
{
  "verdict": {
    "decision": "",
    "confidence": 0,
    "reasons": [],
    "conditions_to_proceed": [],
    "executive_summary": ""
  }
}

# Regla final
Devuelve únicamente JSON válido.`;

const userPayload = JSON.stringify(input);

const outputSchema = {
  type: "object",
  properties: {
    verdict: {
      type: "object",
      properties: {
        decision: { type: "string" },
        confidence: { type: "number" },
        reasons: { type: "array", items: { type: "string" } },
        conditions_to_proceed: { type: "array", items: { type: "string" } },
        executive_summary: { type: "string" }
      },
      required: ["decision", "confidence", "reasons", "conditions_to_proceed", "executive_summary"]
    }
  },
  required: ["verdict"]
};

return [{ json: { input, system_prompt: systemPrompt, user_payload: userPayload, output_schema: outputSchema } }];

let content = $json.text ?? $json.output ?? $json;

if (typeof content === 'string') {
  content = content.trim();

  if (content.startsWith('```')) {
    content = content
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/, '')
      .replace(/```$/, '')
      .trim();
  }

  content = JSON.parse(content);
}

if (content && typeof content === 'object' && content.__structured__output__object) {
  content = content.__structured__output__object;
}

content.verdict = content.verdict || {};
content.verdict.decision = content.verdict.decision || "";
content.verdict.confidence = typeof content.verdict.confidence === 'number' ? content.verdict.confidence : 0;
content.verdict.reasons = Array.isArray(content.verdict.reasons) ? content.verdict.reasons : [];
content.verdict.conditions_to_proceed = Array.isArray(content.verdict.conditions_to_proceed) ? content.verdict.conditions_to_proceed : [];
content.verdict.executive_summary = content.verdict.executive_summary || "";

return [{ json: content }];

const data = $json;

if (!data.verdict || typeof data.verdict !== 'object') {
  throw new Error('verdict faltante o inválido');
}

return [{ json: data }];
